import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateStatusTransition,
  validateCreateOrderInput,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('validateCreateOrderInput', () => {
    it('should pass for valid input with items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).not.toThrow();
    });

    it('should throw for empty items array', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });

    it('should pass for multiple items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
        }),
      ).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('delivered', 'shipped')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'shipped')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'delivered')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transition', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transition with descriptive message', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition',
      );
      expect(() => validateStatusTransition('delivered', 'shipped')).toThrow(
        'Invalid status transition',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateEmailNotInUse,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const existingUser: User = {
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('User Validators', () => {
  describe('validateEmailNotTaken', () => {
    it('should pass when no existing user has the email', () => {
      expect(() => validateEmailNotTaken('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() => validateEmailNotTaken('alice@example.com', existingUser)).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should pass when no existing user has the email', () => {
      expect(() => validateEmailNotInUse('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already in use', () => {
      expect(() => validateEmailNotInUse('alice@example.com', existingUser)).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { shouldSendEmail } from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

function makePrefs(overrides?: Partial<UserPreferences['email']>): UserPreferences {
  return {
    id: 'prefs-user-1',
    userId: 'user-1',
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: ['order-updates', 'account'],
      ...overrides,
    },
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

describe('Preferences Validators', () => {
  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (null)', () => {
      expect(shouldSendEmail(null, 'order-confirmation')).toBe(true);
    });

    it('should return true when no preferences exist (undefined)', () => {
      expect(shouldSendEmail(undefined, 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      const prefs = makePrefs();
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(true);
      expect(shouldSendEmail(prefs, 'order-status-update')).toBe(true);
      expect(shouldSendEmail(prefs, 'welcome')).toBe(true);
      expect(shouldSendEmail(prefs, 'user-updated')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      const prefs = makePrefs({ enabled: false });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      const prefs = makePrefs({ frequency: 'none' });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makePrefs({ subscribedCategories: ['account'] });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return true for subscribed category only', () => {
      const prefs = makePrefs({ subscribedCategories: ['order-updates'] });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(true);
      expect(shouldSendEmail(prefs, 'welcome')).toBe(false);
    });

    it('should work with daily-digest frequency', () => {
      const prefs = makePrefs({ frequency: 'daily-digest' });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(true);
    });

    it('should work with weekly-digest frequency', () => {
      const prefs = makePrefs({ frequency: 'weekly-digest' });
      expect(shouldSendEmail(prefs, 'welcome')).toBe(true);
    });
  });
});

